def build_position_ids(n_sinks: int, n_recent: int) -> torch.Tensor:
    """Assign position IDs: sinks get 0..n_sinks-1, recent get n_sinks.."""
    sink_pos   = torch.arange(n_sinks)
    recent_pos = torch.arange(n_sinks, n_sinks + n_recent)
    return torch.cat([sink_pos, recent_pos])
